INSERT INTO my_mall.goods (name, intro, category_id, cover_img, detail_content, original_price, selling_price, stock_num, sell_status, create_user, update_user) VALUES
('华为 Mate 70 Pro 旗舰手机', '搭载麒麟9100芯片，卫星通信，商务旗舰首选', 46, '/admin/dist/img/no-img.png', '华为2025年度旗舰机型，搭载自研麒麟9100处理器，性能强劲功耗低。6.8英寸OLED曲面屏，支持卫星通信和北斗卫星消息。后置5000万像素可变光圈主摄，拍照效果出色。适合商务人士和追求旗舰体验的用户，送长辈既有面子又实用。', 799900, 699900, 50, 0, 1, 1),
('华为 nova 14 青春版', '前置6000万自拍镜头，轻薄高颜值，学生党首选', 46, '/admin/dist/img/no-img.png', '专为年轻用户打造的高颜值手机，机身仅重168g厚度6.8mm，单手操作无压力。前置6000万像素自拍镜头，AI美颜算法，拍照自然不假面。256GB大存储，满足日常拍照和追剧需求。适合学生党和年轻白领。', 329900, 279900, 80, 0, 1, 1),
('华为畅享 80 老年智能机', '大字大屏大电池，简易模式一键SOS，送爸妈首选', 46, '/admin/dist/img/no-img.png', '专为老年人设计的智能手机，6.75英寸大屏搭配全局大字模式，看消息不费力。6000mAh超大电池，待机可达7天。侧面实体SOS按键一键求助，远程协助功能让子女随时帮忙。送父母的贴心之选。', 159900, 129900, 100, 0, 1, 1),
('iPhone 17 Pro Max 沙漠金', 'A19 Pro芯片，钛金属机身，影像巅峰之作', 47, '/admin/dist/img/no-img.png', '苹果2025年度机皇，A19 Pro芯片性能领先全行业。钛金属机身轻巧坚固，沙漠金配色低调奢华。后置三摄支持8K视频录制，ProRAW格式适合摄影爱好者。适合追求极致体验的用户，送给女朋友彰显品味。', 1099900, 999900, 30, 0, 1, 1),
('iPhone SE 4 午夜色', 'A17芯片小钢炮，小屏旗舰性价比之选', 47, '/admin/dist/img/no-img.png', '苹果最具性价比的机型，搭载A17芯片性能不妥协。5.4英寸小屏设计单手操控自如，Touch ID指纹解锁安全便捷。适合喜欢小屏的用户和预算有限的学生党，入门苹果生态的最佳选择。', 399900, 349900, 60, 0, 1, 1),
('小米 16 Ultra 徕卡影像', '徕卡光学镜头，骁龙8Gen5，摄影师的随身相机', 51, '/admin/dist/img/no-img.png', '小米与徕卡联合打造的影像旗舰，一英寸大底传感器配合徕卡光学镜头，夜景和街拍效果惊艳。骁龙8Gen5处理器性能拉满，120W快充19分钟充满。适合喜欢手机摄影的年轻用户。', 599900, 549900, 45, 0, 1, 1),
('Redmi Note 14 Pro 学生入门机', '5100mAh大电池，1亿像素，学生党性价比神机', 52, '/admin/dist/img/no-img.png', 'Redmi年度走量神机，1亿像素主摄拍照清晰，5100mAh超大电池续航两天无压力。天玑8300处理器日常使用流畅不卡顿。价格亲民配置良心，学生党入门首选，性价比之王。', 179900, 149900, 120, 0, 1, 1),
('OPPO Reno 14 自拍神机', '前置柔光双摄，AI美颜，拍出自然好气色', 56, '/admin/dist/img/no-img.png', 'OPPO专为自拍打造的Reno系列，前置柔光环配合AI美颜算法，暗光自拍也自然透亮。轻薄机身搭配渐变配色，颜值在线。适合爱自拍的女性用户，送给女朋友记录美好生活。', 299900, 259900, 70, 0, 1, 1),
('vivo X210 游戏电竞手机', '骁龙8Gen5+独显芯片，144Hz电竞屏，游戏党利器', 57, '/admin/dist/img/no-img.png', 'vivo与高通联合调校的电竞手机，骁龙8Gen5搭配独立显示芯片，120帧高画质运行游戏无压力。144Hz电竞屏触控采样率高达720Hz，操作跟手零延迟。液冷散热系统持久游戏不降频。适合重度手游玩家。', 449900, 399900, 55, 0, 1, 1),
('荣耀 Magic 7 均衡旗舰', '骁龙8Gen5，5000mAh青海湖电池，全面均衡无短板', 45, '/admin/dist/img/no-img.png', '荣耀Magic系列主打全面均衡体验，骁龙8Gen5性能充足，5000mAh青海湖电池续航出色。后置5000万三摄系统覆盖全焦段，信号增强芯片保障网络稳定。适合追求稳定可靠体验的上班族。', 499900, 449900, 40, 0, 1, 1),
('一加 14 极客性能旗舰', '2K东方屏，24GB运存，原生安卓体验流畅不将就', 54, '/admin/dist/img/no-img.png', '一加年度旗舰，2K分辨率东方屏显示效果行业顶尖。24GB超大运存加1TB存储，多任务切换丝滑流畅。原生安卓风格系统无广告，极客和程序员的最爱。适合追求纯粹安卓体验的技术爱好者。', 549900, 499900, 35, 0, 1, 1),
('Redmi 13C 百元老年智能机', '大音量扬声器，极简桌面，远程协助，送长辈超值', 52, '/admin/dist/img/no-img.png', '百元价位最值得入手的老年智能机。极简桌面图标大字醒目，来电语音播报防止漏接。大音量扬声器通话清晰，支持远程协助功能子女随时帮操作。5000mAh电池续航一周。送父母送长辈的经济实惠之选。', 69900, 59900, 150, 0, 1, 1);
INSERT INTO my_mall.goods (name, intro, category_id, cover_img, detail_content, original_price, selling_price, stock_num, sell_status, create_user, update_user) VALUES
('迪奥魅惑唇膏 999 正红色', '经典正红，显白不挑皮，气场女王必备色号', 86, '/admin/dist/img/no-img.png', '迪奥经典999号正红色，被称为女王红。丝绒质地顺滑不拔干，薄涂日常元气厚涂气场全开。不挑肤色黄皮白皮都显白。礼盒包装精美适合送给女朋友闺蜜或者犒劳自己。约会通勤聚会百搭色号。', 39900, 35900, 80, 0, 1, 1),
('MAC子弹头唇膏 316 蜜桃豆沙', '温柔豆沙色，日常通勤裸妆必备，素颜也能驾驭', 86, '/admin/dist/img/no-img.png', 'MAC经典子弹头系列316号蜜桃豆沙色，日常通勤万用色号。哑光质地但不拔干，持久度高喝水不沾杯。颜色温柔不张扬，素颜也能涂出门。适合学生党和上班族日常使用，百搭任何妆容。', 22900, 18900, 100, 0, 1, 1),
('完美日记小细跟唇膏 L04 橘调番茄', '奶油橘调元气满满，学生党平价好物，显白一绝', 86, '/admin/dist/img/no-img.png', '完美日记爆款小细跟系列，L04橘调番茄红元气十足。奶油质地顺滑好涂抹，薄涂提气色厚涂显白。细管设计方便补妆携带。价格亲民国货之光，学生党入手无压力，日常使用不心疼。', 9900, 7900, 150, 0, 1, 1),
('祖玛珑蓝风铃淡香水 30ml', '清新铃兰花香，少女感十足，送女友首选礼物', 105, '/admin/dist/img/no-img.png', '祖玛珑最经典的蓝风铃香水，前调蓝风铃清新透亮，中调柿子带来微甜果香，后调白麝香温柔收尾。整体轻盈少女感十足，不浓烈不招摇，适合日常通勤和约会使用。包装精致送礼佳品，送女友送闺蜜几乎零差评。', 69900, 59900, 60, 0, 1, 1),
('香奈儿五号浓香水 50ml', '经典馥郁花香，成熟优雅气质女神专属', 105, '/admin/dist/img/no-img.png', '香奈儿五号百年经典香水，茉莉玫瑰依兰依兰的馥郁花香调，满满的成熟优雅女人味。留香持久一整天，适合重要场合和晚宴使用。送给妈妈或成熟女性长辈，体面又有心意。', 129900, 119900, 30, 0, 1, 1),
('春雨蜂蜜补水面膜 10片装', '天然蜂蜜精华，深层补水保湿，干皮救星', 106, '/admin/dist/img/no-img.png', '韩国春雨经典蜂蜜面膜，天然蜂蜜精华搭配玻尿酸，深度补水锁水效果显著。蚕丝面膜纸轻薄服帖，敷完皮肤水润透亮。适合干皮和换季敏感肌，学生党平价护肤必备。一周用两三次，皮肤水嫩一整天。', 8900, 6900, 200, 0, 1, 1),
('SK-II 前男友面膜 6片装', 'PITERA精华密集修护，重要场合前一晚急救神器', 106, '/admin/dist/img/no-img.png', 'SK-II明星产品前男友面膜，富含PITERA酵母精华，一片含有一瓶神仙水的精华量。敷15分钟皮肤立刻通透水润毛孔细腻肤色均匀。重要场合前一晚敷一片隔天皮肤状态满分。适合有重要约会或面试时急救使用。', 89900, 79900, 40, 0, 1, 1),
('雅诗兰黛DW持妆粉底液 油皮亲妈', '控油遮瑕持久不脱妆，油皮混油皮挚爱粉底', 102, '/admin/dist/img/no-img.png', '雅诗兰黛DW粉底液被誉为油皮亲妈，控油持妆效果行业顶尖。遮瑕力中上能遮盖痘印和毛孔，妆效哑光自然不假面。持妆12小时不暗沉不斑驳。适合油皮和混油皮用户，夏天出汗出油也不怕。', 45900, 39900, 55, 0, 1, 1),
('兰蔻持妆粉底液 干皮救星', '轻薄水润光泽肌，干皮混干皮挚爱底妆', 102, '/admin/dist/img/no-img.png', '兰蔻持妆粉底液主打轻薄水润妆效，含透明质酸成分上妆同时补水保湿。妆感自然光泽肌，仿佛天生好皮肤。SPF25防晒值日常通勤够用。适合干皮和追求自然裸妆感的用户，秋冬干燥季节也不卡粉。', 49900, 43900, 50, 0, 1, 1),
('雪花秀致美气垫BB霜 21号', '韩方草本养肤气垫，上妆即护肤，清透伪素颜', 99, '/admin/dist/img/no-img.png', '雪花秀经典气垫BB霜，蕴含人参和草本精华，上妆同时滋养肌肤。21号自然色适合大多数亚洲肤色。妆感清透伪素颜效果，补妆方便随身携带。适合上班族快速上妆出门，送妈妈送长辈也很合适。', 55900, 48900, 45, 0, 1, 1),
('兰芝雪纱隔离霜 紫色款', '修饰暗黄提亮肤色，素颜霜打底神器', 101, '/admin/dist/img/no-img.png', '兰芝明星隔离霜紫色款，专为亚洲黄皮设计。淡紫色乳霜能中和暗黄提亮肤色，单独使用即可当素颜霜。质地水润好推开，后续上妆更服帖。适合经常熬夜肤色暗沉的上班族和学生党。', 29900, 24900, 75, 0, 1, 1),
('Olay小白瓶美白精华 30ml', '烟酰胺5%科学美白，淡化痘印提亮肤色', 100, '/admin/dist/img/no-img.png', 'Olay明星小白瓶美白精华，含5%高浓度烟酰胺，科学美白淡化黑色素。坚持使用四周可见肤色提亮痘印变淡。清爽不油腻适合所有肤质。性价比极高的美白精华，学生党入手美白第一步的首选。', 32900, 26900, 90, 0, 1, 1),
('SK-II 小灯泡美白精华 50ml', 'PITERA加烟酰胺，贵妇级美白淡斑神器', 100, '/admin/dist/img/no-img.png', 'SK-II小灯泡美白精华，PITERA酵母搭配高浓度烟酰胺，美白淡斑效果业界公认。乳白色精华液带微闪粒子上脸立刻提亮。坚持使用一个月肤色白一个度。价格虽贵但效果确实好，适合有预算的熟龄肌。', 169900, 154900, 25, 0, 1, 1),
('NARS 高潮腮红 4.8g', '经典蜜桃金闪，自然红润好气色，一块用到天荒地老', 103, '/admin/dist/img/no-img.png', 'NARS全球销量第一的腮红色号，蜜桃粉色带细腻金闪。上脸雾面微光泽，仿佛皮肤透出的自然红润。显色度适中新手友好不猴屁股。一块腮红用到天荒地老，适合所有肤色的百搭腮红。', 31900, 27900, 65, 0, 1, 1),
('美宝莲摩天翘睫毛膏 防水款', '纤长卷翘防水不晕，平价睫毛膏之王', 104, '/admin/dist/img/no-img.png', '美宝莲经典摩天翘睫毛膏防水版，刷头弧度贴合眼型，一刷睫毛立刻纤长卷翘。防水配方游泳出汗都不晕染，温水可卸不伤睫毛。价格亲民效果不输大牌，学生党和化妆新手入门必备。', 12900, 9900, 120, 0, 1, 1);
INSERT INTO my_mall.goods (name, intro, category_id, cover_img, detail_content, original_price, selling_price, stock_num, sell_status, create_user, update_user) VALUES
('米家扫地机器人 3C 增强版', '激光导航5000Pa飓风吸力，扫拖一体解放双手', 22, '/admin/dist/img/no-img.png', '米家扫地机器人3C增强版，LDS激光导航精准建图不漏扫。5000Pa飓风级吸力宠物毛发灰尘一吸即净。拖地功能电控水箱均匀出水扫拖一体解放双手。米家APP远程控制定时清扫。适合养宠物的家庭和忙碌的上班族。', 229900, 179900, 60, 0, 1, 1),
('戴森 V16 无线吸尘器', '激光探测微尘，240AW强劲吸力，除螨除尘全能', 23, '/admin/dist/img/no-img.png', '戴森V16旗舰无线吸尘器，激光探测技术让肉眼看不见的微尘无处遁形。240AW超强吸力深层清洁地毯床垫沙发。配备除螨吸头除螨率99%。最长续航60分钟全屋清洁无压力。适合有洁癖和养宠物的精致生活家。', 549900, 499900, 25, 0, 1, 1),
('米家加湿器 Pro 增强版', '5L大容量UV杀菌，静音加湿不扰眠，空调房必备', 27, '/admin/dist/img/no-img.png', '米家加湿器Pro增强版，5L大水箱持续加湿16小时一整晚不用加水。UV-C紫外线杀菌先杀菌再加湿，出雾干净不滋生细菌。噪音低至28分贝不影响睡眠。适合空调房和暖气房使用，缓解皮肤干燥喉咙不适。', 29900, 24900, 85, 0, 1, 1),
('JBL 蓝牙音箱 Flip 8 便携防水', '12小时续航IPX7防水，户外聚会音乐伴侣', 28, '/admin/dist/img/no-img.png', 'JBL Flip 8便携蓝牙音箱，12小时超长续航从早嗨到晚。IPX7级防水泳池边淋雨都不怕。低音澎湃中高音清晰，户外聚会氛围利器。轻巧便携放背包即可，露营野餐海滩出游的音乐伴侣。', 59900, 49900, 70, 0, 1, 1),
('猫王收音机 蓝牙音箱 复古绿', '复古收音机造型，FM调频加蓝牙，书房办公桌格调好物', 28, '/admin/dist/img/no-img.png', '猫王收音机经典复古造型蓝牙音箱，胡桃木外壳搭配金属旋钮质感满满。FM调频收音加蓝牙双模播放。音质温暖适合播放爵士和民谣。放在书房或办公桌上既是音箱也是摆件。适合文艺青年和办公桌美学爱好者。', 39900, 34900, 50, 0, 1, 1),
('米家智能空气炸锅 5.5L', '360度热风循环无油烹饪，低脂健康美食轻松做', 21, '/admin/dist/img/no-img.png', '米家智能空气炸锅5.5L大容量，360度热风循环不用翻面均匀酥脆。无油烹饪比传统油炸减少80%油脂。预设8大菜单一键操作厨房小白也能做美食。适合减脂健身人群和喜欢在家做饭的年轻人。', 45900, 39900, 65, 0, 1, 1),
('德龙全自动咖啡机 ECAM 23.460', '意式浓缩美式一键出品，办公室咖啡角升级之选', 20, '/admin/dist/img/no-img.png', '德龙全自动咖啡机ECAM23.460，15Bar泵压萃取醇正意式浓缩。内置研磨器现磨现冲保留咖啡豆新鲜风味。一键制作拿铁卡布奇诺美式，办公室咖啡角品质升级之选。适合咖啡爱好者和追求品质生活的白领。', 459900, 399900, 15, 0, 1, 1),
('小熊暖风机 家用静音速热', '3秒速热倾倒断电，南方冬天取暖神器', 26, '/admin/dist/img/no-img.png', '小熊速热暖风机，PTC陶瓷发热3秒速热无需等待。两档功率可调节摇头送暖覆盖面积更大。倾倒自动断电安全放心，体积小巧桌下床边都能放。适合南方没有暖气的冬天取暖使用。', 15900, 12900, 100, 0, 1, 1),
('美的破壁豆浆机 1.75L', '免泡豆免过滤一键出浆，营养早餐好帮手', 25, '/admin/dist/img/no-img.png', '美的破壁豆浆机1.75L大容量，免泡豆免过滤一键出浆操作简单。破壁技术豆渣细腻无需过滤，营养充分保留不浪费。还能做米糊果汁浓汤一机多用。适合注重健康饮食的家庭，给爸妈买一台改善早餐。', 59900, 49900, 40, 0, 1, 1),
('米家空气净化器 Pro H', '除甲醛除霾除菌，新房装修后必备', 31, '/admin/dist/img/no-img.png', '米家空气净化器Pro H，高效滤芯可过滤PM2.5甲醛细菌病毒。适用面积72平米覆盖客厅卧室。OLED触摸屏实时显示PM2.5数值。新房装修后除甲醛利器，过敏季防雾霾防花粉。', 179900, 149900, 35, 0, 1, 1),
('松下蒸烤箱 NU-SC360B', '蒸烤炸一体30L大容量，厨房全能选手', 29, '/admin/dist/img/no-img.png', '松下蒸烤箱NU-SC360B，蒸烤炸一体兼顾多种烹饪方式。30L大容量一次搞定一家人的饭菜。直喷蒸汽蒸鱼蒸菜鲜嫩多汁，热风烘烤面包蛋糕不翻车。适合喜欢在家研究美食的烹饪爱好者。', 259900, 229900, 20, 0, 1, 1),
('戴森卷发棒 Airwrap 多功能', '康达效应气流自动卷发不伤发，送礼天花板', 30, '/admin/dist/img/no-img.png', '戴森Airwrap多功能美发器，利用康达效应气流自动吸附头发卷发无需技巧。低温气流定型不伤发质，吹干卷发顺发三合一。多种风嘴配件满足不同造型需求。价格虽贵但体验惊艳，送给女朋友或老婆的终极礼物。', 429900, 399900, 15, 0, 1, 1);
INSERT INTO my_mall.goods (name, intro, category_id, cover_img, detail_content, original_price, selling_price, stock_num, sell_status, create_user, update_user) VALUES
('优衣库轻薄羽绒服 男款', '轻便保暖可收纳，秋冬通勤百搭外套', 76, '/admin/dist/img/no-img.png', '优衣库经典轻薄羽绒服，选用90%白鹅绒填充蓬松保暖。自重仅200g可收纳成小包携带方便。简约立领设计百搭日常通勤，内搭衬衫或毛衣都好看。适合秋冬季节穿着轻便不臃肿活动自如。性价比极高人手一件的基础款。', 49900, 39900, 90, 0, 1, 1),
('波司登极寒羽绒服 男款 加厚', '零下30度御寒鹅绒填充，北方过冬必备战袍', 76, '/admin/dist/img/no-img.png', '波司登极寒系列加厚羽绒服，95%白鹅绒填充蓬松度800以上。防风防水面料雨雪天气无压力。蓄热内里锁住体温，零下30度也暖和。多口袋设计实用方便。适合北方严寒地区过冬，送给爸爸保暖御寒。', 159900, 129900, 40, 0, 1, 1),
('太平鸟羊毛呢大衣 男款 商务休闲', '澳洲初剪羊毛双面呢，商务通勤气质之选', 76, '/admin/dist/img/no-img.png', '太平鸟羊毛呢大衣选用澳洲初剪羊毛双面呢面料，手感软糯挺括有型。经典翻领版型修饰身形，商务休闲两穿。中长款长度刚好盖住臀部保暖不压个子。适合上班族通勤穿，搭配衬衫或高领毛衣都显气质。', 89900, 69900, 35, 0, 1, 1),
('MLB棒球服 男款 拼色潮流', '纽约洋基队联名款，街头潮流百搭单品', 76, '/admin/dist/img/no-img.png', 'MLB棒球服纽约洋基队联名款，拼色设计街头感十足。纯棉面料亲肤透气春秋穿着刚刚好。宽松版型搭配牛仔裤或运动裤都好看。适合追求潮流的学生党和年轻人，情侣款女生穿也很有范。', 59900, 47900, 55, 0, 1, 1),
('骆驼冲锋衣 男款 三合一可拆卸', '防风防水可拆卸内胆，户外徒步登山必备', 76, '/admin/dist/img/no-img.png', '骆驼三合一冲锋衣，外层防风防水可应对小雨天气，内层抓绒保暖可拆卸单穿。一衣三穿春夏秋都能用。立体剪裁活动自如不束缚。适合喜欢户外运动徒步爬山的用户，出差旅行应对多变天气。', 69900, 54900, 60, 0, 1, 1),
('北面羽绒服 男款 1996经典复刻', '700蓬鹅绒经典款，雪山图案街拍出片神器', 76, '/admin/dist/img/no-img.png', '北面1996经典复刻款羽绒服，700蓬松度鹅绒填充轻盈保暖。经典雪山图案辨识度极高街拍出片有面子。防风袖口和下摆锁住热量减少流失。适合追求潮流又怕冷的年轻人，冬天出街又暖又帅。', 199900, 169900, 25, 0, 1, 1),
('Nike Air Zoom Pegasus 41 男跑鞋', 'ZoomX泡棉加Air气垫，回弹缓震专业慢跑鞋', 78, '/admin/dist/img/no-img.png', 'Nike飞马41代专业慢跑鞋，ZoomX泡棉搭配前后掌Air Zoom气垫，回弹出色缓震到位。Flywire飞线包裹脚感贴合，工程网面透气不闷脚。适合日常五到十公里慢跑和健身房训练使用。', 99900, 79900, 70, 0, 1, 1),
('阿迪达斯 Ultraboost 23 男跑鞋', 'Boost中底踩屎感十足，日常通勤慢跑两不误', 78, '/admin/dist/img/no-img.png', '阿迪达斯UB23跑鞋，Boost中底被跑友称为踩屎感，缓震回弹业界标杆。Primeknit编织鞋面如袜子般贴合长时间穿着不磨脚。适合日常通勤走路和轻度慢跑，久站上班族穿了就不想换鞋。', 89900, 69900, 55, 0, 1, 1),
('亚瑟士 GEL-KAYANO 31 男稳定跑鞋', 'GEL缓震胶支撑稳定，扁平足外翻跑者福音', 78, '/admin/dist/img/no-img.png', '亚瑟士KAYANO31旗舰稳定跑鞋，后跟GEL缓震胶吸收跑动冲击力保护膝盖。内侧DUOMAX支撑柱矫正外翻步态，扁平足和低足弓跑者的保护神。工程网面透气包裹到位。适合大体重和扁平足跑者日常训练。', 129900, 109900, 30, 0, 1, 1),
('new balance 574 灰色 经典复古鞋', '百搭灰色复古慢跑鞋，日系穿搭必备单品', 98, '/admin/dist/img/no-img.png', '新百伦574经典灰配色，复古慢跑鞋鼻祖，日系穿搭街拍出镜率最高鞋款。皮革和网面拼接质感好，ENCAP中底日常走路舒适不累。百搭配色牛仔裤工装裤运动裤都能搭。适合学生党和日常通勤穿着的经典款。', 79900, 64900, 65, 0, 1, 1),
('匡威 Chuck 70 高帮帆布鞋 黑色', '70s复古鞋型加厚鞋底，一年四季百搭王', 98, '/admin/dist/img/no-img.png', '匡威Chuck70高帮帆布鞋，70s复古鞋型橡胶底加厚舒适度提升。黑色经典百搭所有衣服，高帮设计修饰腿型。帆布材质透气夏天穿也不闷。从学生到明星都穿的基础款，一年四季搭配万能选手。', 59900, 49900, 100, 0, 1, 1),
('斯凯奇老爹鞋 女款 厚底增高', '复古厚底增高4cm，显腿长百搭舒适', 98, '/admin/dist/img/no-img.png', '斯凯奇复古老爹鞋女款，厚底设计悄悄增高4cm修饰腿长。记忆海绵鞋垫踩上去柔软回弹逛街一天不累脚。白色拼灰配色百搭所有风格。适合日常通勤逛街和旅游暴走，舒适度拉满的日常鞋款。', 69900, 55900, 75, 0, 1, 1);
